#include <bits/stdc++.h>
using namespace std;
const int M=25000;
int t,n,a[102],ans;
bool dp[102][25003];
int main(){
	scanf("%d",&t);
	while(t--){
		scanf("%d",&n);
		ans=n;
		for(int i=1;i<=n;i++)
			scanf("%d",&a[i]);
		sort(a+1,a+n+1);
		dp[0][0]=1;
		for(int i=1;i<=n;i++){
			if(dp[i-1][a[i]])
				ans--;
			for(int j=0;j<=M;j++)
				if(j>=a[i])
					dp[i][j]=max(dp[i-1][j],dp[i][j-a[i]]);
				else
					dp[i][j]=dp[i-1][j];
		}
		printf("%d\n",ans);
	}
	return 0; 
}
